const rows = $('Get row(s) in sheet').all().map(item => item.json);
const rates = $('HTTP Request').first().json.conversion_rates;

const validAlvRates = [0, 10, 13.5, 25.5];
const errors = [];
const supplierMap = {};
const seen = [];

rows.forEach((row, i) => {
  const currency = row['Valuutta'] || 'EUR';
  const rate = currency === 'EUR' ? 1 : (1 / rates[currency]);

  if (!rate) {
    errors.push(`Rivi ${i+2} (${row['Toimittaja']}): Tuntematon valuutta ${currency}`);
    seen.push({ toimittaja: row['Toimittaja'], nettoEur: 0, pvm: new Date(row['Päivämäärä']), rivi: i+2 });
    return;
  }

  const nettoEur = Math.round(parseFloat(row['Netto']) * rate * 100) / 100;
  const alvRate = parseFloat(row['ALV %']);
  const alvSummaEur = Math.round(parseFloat(row['ALV-summa']) * rate * 100) / 100;
  const laskettuAlv = Math.round(nettoEur * (alvRate / 100) * 100) / 100;

  // Parse date properly - handle both YYYY-MM-DD and DD.MM.YYYY formats
  let laskuPvm;
  const dateStr = String(row['Päivämäärä']);
  if (dateStr.includes('-')) {
    laskuPvm = new Date(dateStr);
  } else if (dateStr.includes('.')) {
    const parts = dateStr.split('.');
    laskuPvm = new Date(parts[2], parts[1] - 1, parts[0]);
  } else {
    laskuPvm = new Date(dateStr);
  }

  // Tarkistus 1: ALV-% sallittu
  if (!validAlvRates.includes(alvRate)) {
    errors.push(`Rivi ${i+2} (${row['Toimittaja']}): Virheellinen ALV-% ${alvRate}`);
  }

  // Tarkistus 2: ALV-summa täsmää
  if (Math.abs(laskettuAlv - alvSummaEur) > 0.05) {
    errors.push(`Rivi ${i+2} (${row['Toimittaja']}): ALV-summa ei täsmää — laskettu ${laskettuAlv}€, ilmoitettu ${alvSummaEur}€`);
  }

  // Tarkistus 3: Duplikaattiriski - tarkista ENNEN lisäämistä seen-listaan
  for (let j = 0; j < seen.length; j++) {
    const s = seen[j];
    if (s.toimittaja === row['Toimittaja']) {
      const amountDiff = Math.abs(s.nettoEur - nettoEur);
      // Use 1% tolerance or 5 EUR, whichever is larger
      const tolerance = Math.max(5, nettoEur * 0.01);
      if (amountDiff <= tolerance) {
        // Calculate days difference for reporting (no longer filtering by it)
        const daysDiff = Math.abs((laskuPvm - s.pvm) / (1000 * 60 * 60 * 24));
        const pvmStr = s.pvm.toISOString().split('T')[0];
        const currPvmStr = laskuPvm.toISOString().split('T')[0];
        errors.push(`Rivi ${i+2} (${row['Toimittaja']}): Mahdollinen duplikaatti — sama summa ${nettoEur.toFixed(2)}€ (ero ${amountDiff.toFixed(2)}€) ${daysDiff.toFixed(0)} päivän välillä (aiempi rivi ${s.rivi}, pvm ${pvmStr} vs ${currPvmStr})`);
        break;
      }
    }
  }

  seen.push({ toimittaja: row['Toimittaja'], nettoEur, pvm: laskuPvm, rivi: i+2 });

  // Aggregointi toimittajittain
  if (!supplierMap[row['Toimittaja']]) {
    supplierMap[row['Toimittaja']] = { laskuja: 0, yhtEur: 0, virheet: 0 };
  }
  supplierMap[row['Toimittaja']].laskuja++;
  supplierMap[row['Toimittaja']].yhtEur = Math.round((supplierMap[row['Toimittaja']].yhtEur + nettoEur) * 100) / 100;
});

return [{
  json: {
    ok: errors.length === 0,
    virheet: errors,
    toimittajat: supplierMap,
    tarkistettu_riveja: rows.length,
    kaytetyt_kurssit: {
      USD: (1 / rates['USD']).toFixed(4),
      GBP: (1 / rates['GBP']).toFixed(4),
      SEK: (1 / rates['SEK']).toFixed(4)
    },
    kurssi_aika: new Date().toISOString()
  }
}];
